from collections import defaultdict, deque
def calc_equation(equations, values, queries):
    g = defaultdict(list)
    for (a, b), w in zip(equations, values):
        g[a].append((b, w))
        g[b].append((a, 1.0 / w))
    def query(s, t):
        if s not in g or t not in g:
            return -1.0
        if s == t:
            return 1.0
        q = deque([(s, 1.0)])
        seen = {s}
        while q:
            u, val = q.popleft()
            if u == t:
                return val
            for v, w in g[u]:
                if v not in seen:
                    seen.add(v)
                    q.append((v, val * w))
        return -1.0
    return [query(a, b) for a, b in queries]

